import java.util.Scanner;
import java.lang.Math;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int q = scanner.nextInt();
            double[][] semiDiscs = new double[n][2];
            for (int i = 0; i < n; i++) {
                semiDiscs[i][0] = scanner.nextDouble();
                semiDiscs[i][1] = scanner.nextDouble();
            }
            for (int i = 0; i < q; i++) {
                double xi = scanner.nextDouble();
                double yi = scanner.nextDouble();
                double ri = scanner.nextDouble();
                double area = 0;
                for (int j = 0; j < n; j++) {
                    double dx = xi - semiDiscs[j][0];
                    double dy = yi;
                    double distance = Math.sqrt(dx * dx + dy * dy);
                    if (distance <= ri + semiDiscs[j][1]) {
                        double overlapArea = 0;
                        if (distance <= ri - semiDiscs[j][1]) {
                            overlapArea = Math.PI * semiDiscs[j][1] * semiDiscs[j][1] / 2;
                        } else {
                            double angle = Math.acos((ri * ri + distance * distance - semiDiscs[j][1] * semiDiscs[j][1]) / (2 * ri * distance));
                            overlapArea = (angle - Math.sin(angle * 2) / 2) * ri * ri;
                        }
                        area += overlapArea;
                    }
                }
                System.out.printf("%.6f\n", area);
            }
        }
    }
}

